done.script:
var fd = tree.root.get_node_or_null("/root/Main/FormationsDialog")
if fd == null:
	return false
var q = [fd]
while not q.is_empty():
	var nd = q.pop_back()
	if nd is OptionButton and nd.item_count > 0 and nd.get_item_text(0) == "(Unattached)":
		return nd.selected == 1
	for c in nd.get_children():
		q.append(c)
return false

var fd = tree.root.get_node_or_null("/root/Main/FormationsDialog")
if fd == null:
	return false
var q = [fd]
while not q.is_empty():
	var nd = q.pop_back()
	if nd is CheckBox and str(nd.text).begins_with("Boyz") and not ("Reserves" in str(nd.text)):
		return nd.button_pressed
	for c in nd.get_children():
		q.append(c)
return false
